import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { obtenerVentas } from '../services/ventaService'; // Debes crear esta función en tu service

const Reportes = () => {
    const navigate = useNavigate();
    const [ventas, setVentas] = useState([]);
    const [filtro, setFiltro] = useState('dia'); // dia, mes, año
    const [busquedaFecha, setBusquedaFecha] = useState(new Date().toISOString().split('T')[0]);

    useEffect(() => {
        if (!localStorage.getItem('usuarioLogueado')) {
            navigate("/");
        } else {
            cargarVentas();
        }
    }, [navigate, filtro, busquedaFecha]);

    const cargarVentas = async () => {
        const data = await obtenerVentas(); // Trae todas las ventas de la DB
        const filtradas = data.filter(v => {
            const fechaV = new Date(v.fechaVenta);
            const fechaF = new Date(busquedaFecha);
            
            if (filtro === 'dia') {
                return fechaV.toDateString() === fechaF.toDateString();
            } else if (filtro === 'mes') {
                return fechaV.getMonth() === fechaF.getMonth() && fechaV.getFullYear() === fechaF.getFullYear();
            } else {
                return fechaV.getFullYear() === fechaF.getFullYear();
            }
        });
        setVentas(filtradas);
    };

    // Cálculos Financieros
    const totalVendido = ventas.reduce((acc, v) => acc + v.total, 0);
    // Nota: Necesitas que el objeto Venta guarde o recupere el precioCompra del momento
    const totalGastos = ventas.reduce((acc, v) => acc + (v.precioCompra * v.cantidad), 0);
    const gananciaNeta = totalVendido - totalGastos;

    return (
        <div style={{ padding: '30px', fontFamily: 'Arial', maxWidth: '1200px', margin: '0 auto' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
                <button onClick={() => navigate("/inventario")} style={{ backgroundColor: '#6c757d', color: 'white', padding: '10px 15px', border: 'none', borderRadius: '8px', cursor: 'pointer' }}>⬅️ Inventario</button>
                <h2 style={{ color: '#007bff' }}>📈 Reporte de Ganancias - Isla Tecnológica</h2>
            </div>

            {/* FILTROS */}
            <div style={{ display: 'flex', gap: '15px', background: '#f8f9fa', padding: '20px', borderRadius: '12px', marginBottom: '25px' }}>
                <div>
                    <label><b>Margen de tiempo:</b></label><br/>
                    <select value={filtro} onChange={(e) => setFiltro(e.target.value)} style={{ padding: '10px', borderRadius: '8px', marginTop: '5px' }}>
                        <option value="dia">Por Día</option>
                        <option value="mes">Por Mes</option>
                        <option value="año">Por Año</option>
                    </select>
                </div>
                <div>
                    <label><b>Seleccionar Fecha:</b></label><br/>
                    <input type="date" value={busquedaFecha} onChange={(e) => setBusquedaFecha(e.target.value)} style={{ padding: '10px', borderRadius: '8px', marginTop: '5px' }} />
                </div>
            </div>

            {/* TARJETAS DE ESTADÍSTICA */}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '20px', marginBottom: '30px' }}>
                <div style={{ background: '#fff', padding: '20px', borderRadius: '12px', boxShadow: '0 4px 10px rgba(0,0,0,0.1)', textAlign: 'center' }}>
                    <h4 style={{ margin: '0', color: '#666' }}>Venta Total</h4>
                    <h2 style={{ color: '#007bff' }}>${totalVendido.toFixed(2)}</h2>
                </div>
                <div style={{ background: '#fff', padding: '20px', borderRadius: '12px', boxShadow: '0 4px 10px rgba(0,0,0,0.1)', textAlign: 'center' }}>
                    <h4 style={{ margin: '0', color: '#666' }}>Gastos (Inversión)</h4>
                    <h2 style={{ color: '#dc3545' }}>${totalGastos.toFixed(2)}</h2>
                </div>
                <div style={{ background: '#fff', padding: '20px', borderRadius: '12px', boxShadow: '0 4px 10px rgba(0,0,0,0.1)', border: '2px solid #28a745', textAlign: 'center' }}>
                    <h4 style={{ margin: '0', color: '#666' }}>Ganancia Neta</h4>
                    <h2 style={{ color: '#28a745' }}>${gananciaNeta.toFixed(2)}</h2>
                </div>
            </div>

            {/* TABLA DETALLADA */}
            <table style={{ width: '100%', borderCollapse: 'collapse', background: '#fff', borderRadius: '12px', overflow: 'hidden', boxShadow: '0 4px 10px rgba(0,0,0,0.1)' }}>
                <thead style={{ background: '#007bff', color: 'white' }}>
                    <tr>
                        <th style={{ padding: '15px' }}>Fecha/Hora</th>
                        <th>Producto</th>
                        <th>Cant.</th>
                        <th>Vendedor</th>
                        <th>Venta ($)</th>
                        <th>Ganancia ($)</th>
                    </tr>
                </thead>
                <tbody>
                    {ventas.map((v, i) => (
                        <tr key={i} style={{ borderBottom: '1px solid #eee' }}>
                            <td style={{ padding: '12px', textAlign: 'center' }}>{new Date(v.fechaVenta).toLocaleString()}</td>
                            <td>{v.nombreProducto}</td>
                            <td style={{ textAlign: 'center' }}>{v.cantidad}</td>
                            <td style={{ textAlign: 'center' }}><b>{v.vendedorMatricula}</b></td>
                            <td style={{ textAlign: 'right', paddingRight: '20px' }}>${v.total.toFixed(2)}</td>
                            <td style={{ textAlign: 'right', paddingRight: '20px', color: 'green', fontWeight: 'bold' }}>
                                ${(v.total - (v.precioCompra * v.cantidad)).toFixed(2)}
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default Reportes;
